const data = $input.first().json;
const proyectoArr = Array.isArray(data) ? data : [data];

if (proyectoArr.length === 0 || !proyectoArr[0].id) {
  throw new Error(`Proyecto no encontrado: ${$('Webhook Cierre Proyecto').first().json.body.id_proyecto}`);
}

const proyecto = proyectoArr[0];
const pres = proyecto.presupuestos_cabecera || {};
const cliente = pres.clientes || {};
const cierre = proyecto.cierres_proyectos || {};

// Construir texto descriptivo rico para máxima cobertura semántica
// Este texto es lo que busca el Agente Jarvis cuando busca proyectos similares
const partes = [
  // Descripción principal del stand
  `Stand ${pres.tipo_stand || 'personalizado'} de ${pres.m2_superficie || 0}m² nivel ${pres.nivel_densidad || 'medio'} para ${pres.nombre_feria || 'feria'}.`,

  // Datos físicos
  `Superficie: ${pres.m2_superficie || 0}m². Altura: ${pres.altura_stand_m || 2.5}m. Estilo: ${pres.estilo_stand || 'moderno'}.`,

  // Recinto y cliente
  pres.recinto_ferial ? `Recinto: ${pres.recinto_ferial}.` : '',
  cliente.sector_industrial ? `Sector del cliente: ${cliente.sector_industrial}.` : '',

  // Método de presupuestación
  pres.metodo_presupuestacion ? `Método de presupuestación: ${pres.metodo_presupuestacion}.` : '',

  // Datos económicos
  pres.total_presupuesto ? `Presupuesto total: ${pres.total_presupuesto}€.` : '',
  cierre.ingreso_total_real ? `Ingreso real: ${cierre.ingreso_total_real}€.` : '',
  cierre.margen_real_porcentaje ? `Margen real: ${cierre.margen_real_porcentaje}%.` : '',

  // Rentabilidad vs estimado
  cierre.desviacion_beneficio_porcentaje
    ? `Desviación vs presupuesto: ${cierre.desviacion_beneficio_porcentaje > 0 ? '+' : ''}${cierre.desviacion_beneficio_porcentaje}%.`
    : '',

  // Valoración del cliente
  cierre.valoracion_cliente ? `Valoración del cliente: ${cierre.valoracion_cliente}/5.` : '',

  // Lecciones aprendidas (muy valioso para futuros presupuestos)
  cierre.lecciones_aprendidas ? `Lecciones aprendidas: ${cierre.lecciones_aprendidas}` : '',

  // Notas del presupuesto original
  pres.notas_internas ? `Notas del proyecto: ${pres.notas_internas}` : ''
];

const textoVectorizar = partes.filter(p => p && p.trim() !== '').join(' ');

return [{
  json: {
    id_proyecto: proyecto.id,
    id_presupuesto: pres.id,
    codigo_proyecto: proyecto.codigo_proyecto_interno,
    nombre_feria: pres.nombre_feria,
    recinto_ferial: pres.recinto_ferial,
    tipo_stand: pres.tipo_stand,
    nivel_densidad: pres.nivel_densidad,
    m2: pres.m2_superficie,
    altura: pres.altura_stand_m,
    estilo: pres.estilo_stand,
    sector_cliente: cliente.sector_industrial,
    total_presupuesto: pres.total_presupuesto,
    ingreso_real: cierre.ingreso_total_real,
    margen_real: cierre.margen_real_porcentaje,
    desviacion: cierre.desviacion_beneficio_porcentaje,
    valoracion_cliente: cierre.valoracion_cliente,
    fecha_feria: pres.fecha_inicio_feria,
    fecha_cierre: cierre.fecha_cierre_oficial,
    anio: pres.fecha_inicio_feria ? new Date(pres.fecha_inicio_feria).getFullYear() : new Date().getFullYear(),
    texto_a_vectorizar: textoVectorizar
  }
}];

const embeddingResponse = $input.first().json;
const proyecto = $('Construir Texto Proyecto').first().json;

const vector = embeddingResponse.data?.[0]?.embedding;
if (!vector) throw new Error(`Error embedding proyecto: ${proyecto.codigo_proyecto}`);

// Usamos el id_presupuesto como ID del punto Qdrant
// (es el más estable y único del proyecto)
const puntoId = proyecto.id_presupuesto || proyecto.id_proyecto;

const punto = {
  id: puntoId,
  vector: vector,
  payload: {
    content: proyecto.texto_a_vectorizar,
    id_proyecto: proyecto.id_proyecto,
    id_presupuesto: proyecto.id_presupuesto,
    codigo_proyecto: proyecto.codigo_proyecto,
    // Datos del evento
    nombre_feria: proyecto.nombre_feria || '',
    recinto_ferial: proyecto.recinto_ferial || '',
    fecha_feria: proyecto.fecha_feria || null,
    anio: proyecto.anio,
    // Características físicas del stand
    tipo_stand: proyecto.tipo_stand || '',
    nivel_densidad: proyecto.nivel_densidad || '',
    m2: parseFloat(proyecto.m2) || 0,
    altura: parseFloat(proyecto.altura) || 2.5,
    estilo: proyecto.estilo || '',
    // Datos del cliente
    sector_cliente: proyecto.sector_cliente || '',
    // Datos económicos — muy útiles para calibrar presupuestos futuros
    total_presupuesto: parseFloat(proyecto.total_presupuesto) || 0,
    ingreso_real: parseFloat(proyecto.ingreso_real) || 0,
    margen_real_porcentaje: parseFloat(proyecto.margen_real) || 0,
    desviacion_porcentaje: parseFloat(proyecto.desviacion) || 0,
    valoracion_cliente: proyecto.valoracion_cliente || null,
    // Metadatos
    fecha_cierre: proyecto.fecha_cierre || null,
    activo: true,
    coleccion: 'proyectos_historicos',
    fecha_indexacion: new Date().toISOString()
  }
};

return [{ json: { punto, codigo_proyecto: proyecto.codigo_proyecto, id_punto: puntoId } }];

const qdrantResponse = $input.first().json;
const proyectoData = $('Construir Punto Proyecto').first().json;

const exito = qdrantResponse.status === 'ok';

return [{
  json: {
    success: exito,
    coleccion: 'proyectos_historicos',
    codigo_proyecto: proyectoData.codigo_proyecto,
    id_punto_qdrant: proyectoData.id_punto,
    mensaje: exito
      ? `Proyecto ${proyectoData.codigo_proyecto} indexado en Qdrant. Jarvis aprenderá de este proyecto en futuras búsquedas.`
      : `Error al indexar proyecto ${proyectoData.codigo_proyecto}`,
    qdrant_status: qdrantResponse.status,
    timestamp: new Date().toISOString()
  }
}];
